#!/usr/bin/env python3
"""One-shot, fail-closed bootstrap for AEGIS Experiment Admission Gate v0.1."""
from __future__ import annotations

import base64
import gzip
import hashlib
import json
from pathlib import Path

PAYLOAD = """"""
EXPECTED = {
  ".aegis/claims-ledger.json": "c09e05033567389a7f68c0364247d512ec0fa126a481f0ee3d0f6fd1e5b8ef1b",
  ".aegis/experiment-plan.schema.json": "d7caebcfe9429212b4b3718b2165927c5d6673be8fa17473aadd6cb2cbaf3318",
  ".aegis/experiments/admission-gate-v0.1.json": "8ebe2419d4f02eab5fcf7e94dae3994d3f128c51c2997db5bf1adc69b6c1a565",
  ".github/workflows/experiment-admission.yml": "428dfbd38ac1d265ee0c5c7d2d723e3e58d2f6b2f31d5da20d671b130c3f6953",
  "sovereign-omega-v2/scripts/validate-experiment-plan.ts": "12e0e7d0733fa4d0c821b3810ea138670404da301fd85e59468ffb5abc4d5b33",
  "sovereign-omega-v2/src/sovereignty/experiment-admission.ts": "da8cedbb00f6b67bcf7862192a15379289a7ca4520016b6aad2f372fab7c4e83",
  "sovereign-omega-v2/test/unit/experiment-admission.test.ts": "7c6e6eccd254cc552ad15f7263ab789f21ed94e4311eb6fb66c9abb514f46bfd"
}

def main() -> int:
    decoded = gzip.decompress(base64.b64decode(PAYLOAD))
    files = json.loads(decoded)
    if set(files) != set(EXPECTED):
        raise SystemExit("bootstrap payload path set mismatch")
    for path, content in files.items():
        digest = hashlib.sha256(content.encode()).hexdigest()
        if digest != EXPECTED[path]:
            raise SystemExit(f"bootstrap digest mismatch for {path}")
        target = Path(path)
        if target.exists():
            raise SystemExit(f"refusing to overwrite existing path {path}")
        target.parent.mkdir(parents=True, exist_ok=True)
        target.write_text(content, encoding="utf-8")
    print(f"materialized {len(files)} admission-gate files")
    return 0

if __name__ == "__main__":
    raise SystemExit(main())
